module top_module (
    input [2:0] s,
    output reg obf_c
);

    always @(*) begin
        case (s)
            3'b000: obf_c = 1;
            3'b001: obf_c = 0;
            3'b010: obf_c = 1;
            3'b011: obf_c = 0;
            3'b100: obf_c = 1;
            3'b101: obf_c = 0;
            3'b110: obf_c = 1;
            3'b111: obf_c = 0;
            default: obf_c = 0; // Default case
        endcase
    end
endmodule
